import { Route, Routes, useNavigate } from 'react-router-dom';
import './App.css';
import Modal from './components/modal/Modal';
import { cloneElement, useState } from 'react';
import { Button } from '../src/style/style.Components';

function App() {
  const [showmodal, setShowModal] = useState(false);
  const navigation = useNavigate()

  const back = () => {
    navigation(-1)
  }

  let title = 'salom from to app'

  return (
  <div className='App'>

    <button onClick={() => navigation('modal')}>App</button>

    <Button onClick={() => setShowModal(true)}>
      open Modal
    </Button>

    <Routes>
      <Route path='modal' element={<Modal title={title} back={back}/>}/>
    </Routes>
    {/* <Modal>
      <h1>Nuriddin</h1>
